// Solution
function validatePortMappings(portMappings) {
    let serviceNames = new Set();
    for (let i = 0; i < portMappings.length; i++) {
        let parts = portMappings[i].split(':');
        let serviceName = parts[0];
        let port = parts[1].split('/')[0];
        if (serviceNames.has(serviceName)) {
            return false;
        }
        let portNumber = parseInt(port);
        if (portNumber < 1 || portNumber > 65535) {
            return false;
        }
        serviceNames.add(serviceName);
    }
    return true;
}

